import { Component } from '@angular/core';
//const {sign} = require('jsonwebtoken);

// decorator function
@Component({
  selector: 'app-root',
  templateUrl: './app.component.html',
  //template: '<h3>nhantt</h3>',
  styleUrls: ['./app.component.css']
  //styles:[]
})

export class AppComponent {
  value = 0;
  title = 'Nhantt';
  company = {
    name: 'KPT Training',
    addr: '92 LTR'
  };
  imageSrc = 'https://www.w3schools.com/angular/pic_angular.jpg';
  showTitle(){
    console.log(this.title);
  }
  incr(){
    this.value = this.value+1;
  }
  txtEmail = '';
  txtEn = '';
  txtVn = '';
  isLoggedIn = true;
  subjects = ['Nodejs', 'Angular', 'React', 'Android'];
  currentStyle = {
    color: 'green',
    fontweight: 'bold'
  };
  currentClass = {
    daThuoc: true
  }
  words = [
    {en: 'one', vn: 'mot', isMemorized: true},
    {en: 'two', vn: 'hai', isMemorized: false},
    {en: 'three', vn: 'ba', isMemorized: true}
  ];
  changeStatus() {
    this.isLoggedIn = !this.isLoggedIn;
  };
  addWord() {
    this.words.push({en:this.txtEn, vn: this.txtVn, isMemorized: false});
    this.txtEn = '';
    this.txtVn = '';
  };
  removeWord(en) {
    const index =  this.words.findIndex(word => word.en === en);
    this.words.splice(index, 1);
  }
}
